const input = $input.first().json || {};
const headers = input.headers || {};
const body = input.body || {};
const apiKey = String(headers['x-crm-key'] || headers['X-Crm-Key'] || '').trim();
const expected = String($env.CRM_API_KEY || '').trim();
const action = String(body.action || '').trim();
const recordId = Number(body.recordId || 0);
const backupId = String(body.backupId || '').trim();
const reason = String(body.reason || '').trim();
const operatorName = String(body.operatorName || '').trim();
const limit = Math.min(Math.max(parseInt(body.limit, 10) || 100, 1), 200);
const allowedFields = ['tx_date', 'legacy_book_id', 'customer_name', 'tx_type', 'amount', 'tax', 'memo', 'slip_no', 'debit_account', 'credit_account', 'ledger', 'tx_year'];
const rawChanges = body.changes && typeof body.changes === 'object' ? body.changes : {};
const changes = {};
for (const key of allowedFields) {
  if (rawChanges[key] !== undefined) changes[key] = rawChanges[key];
}

function fail(status, message) {
  return [{ json: { _status: status, _error: true, message } }];
}

if (!apiKey || !expected || apiKey !== expected) {
  return fail(401, '인증에 실패했습니다.');
}

if (!['update', 'delete', 'restore', 'listBackups'].includes(action)) {
  return fail(400, '허용되지 않는 작업입니다.');
}

if (action === 'listBackups') {
  return [{ json: { _status: 200, _error: false, action, limit, operatorName } }];
}

if (action === 'restore') {
  if (!backupId) return fail(400, 'backupId가 필요합니다.');
  if (!operatorName) return fail(400, '작업자명이 필요합니다.');
  return [{ json: { _status: 200, _error: false, action, backupId, operatorName } }];
}

if (!Number.isFinite(recordId) || recordId <= 0) {
  return fail(400, 'recordId가 올바르지 않습니다.');
}
if (!reason) return fail(400, '사유를 입력해주세요.');
if (!operatorName) return fail(400, '작업자명이 필요합니다.');
if (action === 'update' && Object.keys(changes).length === 0) {
  return fail(400, '변경할 값이 없습니다.');
}

return [{
  json: {
    _status: 200,
    _error: false,
    action,
    recordId,
    reason,
    operatorName,
    changes,
    limit,
    nocodbUrl: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pu0mwk97kac8a5p/mtxh72a1f4beeac/' + recordId,
    tableUrl: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pu0mwk97kac8a5p/mtxh72a1f4beeac'
  }
}];

const response = $input.first().json || {};
const request = $('Validate Auth & Parse').first().json || {};
const statusCode = Number(response.statusCode || 200);
const body = response.body || {};
function toKstTimestamp(value = new Date()) {
  const parsed = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(parsed.getTime())) return '';
  const kst = new Date(parsed.getTime() + 9 * 60 * 60 * 1000);
  const pad = (n) => String(n).padStart(2, '0');
  return `${kst.getUTCFullYear()}-${pad(kst.getUTCMonth() + 1)}-${pad(kst.getUTCDate())}T${pad(kst.getUTCHours())}:${pad(kst.getUTCMinutes())}:${pad(kst.getUTCSeconds())}+09:00`;
}
if (statusCode >= 400 || !body || !body.Id) {
  return [{ json: { _status: statusCode || 404, _error: true, message: body.msg || body.message || '원본 거래를 찾지 못했습니다.' } }];
}
const workflowStaticData = $getWorkflowStaticData('global');
const backups = Array.isArray(workflowStaticData.legacyTxHistoryBackups) ? workflowStaticData.legacyTxHistoryBackups : [];
const backupId = 'txb-' + Date.now() + '-' + request.recordId + '-' + Math.random().toString(36).slice(2, 8);
backups.unshift({
  backupId,
  action: request.action,
  recordId: request.recordId,
  createdAt: toKstTimestamp(),
  operatorName: request.operatorName,
  reason: request.reason,
  originalRow: JSON.parse(JSON.stringify(body)),
  changes: request.action === 'update' ? JSON.parse(JSON.stringify(request.changes || {})) : null,
  restoredAt: null,
  restoredRecordId: null
});
workflowStaticData.legacyTxHistoryBackups = backups.slice(0, 1000);
return [{
  json: {
    _status: 200,
    _error: false,
    action: request.action,
    backupId,
    method: request.action === 'update' ? 'PATCH' : 'DELETE',
    nocodbUrl: request.nocodbUrl,
    mutationPayload: request.action === 'update' ? (request.changes || {}) : {},
    operatorName: request.operatorName
  }
}];

const request = $('Validate Auth & Parse').first().json || {};
const workflowStaticData = $getWorkflowStaticData('global');
const backups = Array.isArray(workflowStaticData.legacyTxHistoryBackups) ? workflowStaticData.legacyTxHistoryBackups : [];
const entry = backups.find((item) => item && item.backupId === request.backupId);
if (!entry) {
  return [{ json: { _status: 404, _error: true, message: '복구할 백업을 찾지 못했습니다.' } }];
}
if (entry.restoredAt) {
  return [{ json: { _status: 409, _error: true, message: '이미 복구된 백업입니다.' } }];
}
const originalRow = entry.originalRow || {};
const payload = JSON.parse(JSON.stringify(originalRow));
delete payload.Id;
delete payload.CreatedAt;
delete payload.UpdatedAt;
delete payload.nc_order;
return [{
  json: {
    _status: 200,
    _error: false,
    action: 'restore',
    backupId: entry.backupId,
    method: 'POST',
    nocodbUrl: request.tableUrl || 'https://nocodb.pressco21.com/api/v1/db/data/noco/pu0mwk97kac8a5p/mtxh72a1f4beeac',
    mutationPayload: payload,
    operatorName: request.operatorName
  }
}];

const response = $input.first().json || {};
const statusCode = Number(response.statusCode || 200);
const body = response.body || {};
function safeNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch {
    return {};
  }
}
const backupMeta = safeNodeJson('Backup & Prepare Mutation');
const restoreMeta = safeNodeJson('Prepare Restore Payload');
const action = backupMeta.action || restoreMeta.action || 'update';
const backupId = backupMeta.backupId || restoreMeta.backupId || '';
function toKstTimestamp(value = new Date()) {
  const parsed = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(parsed.getTime())) return '';
  const kst = new Date(parsed.getTime() + 9 * 60 * 60 * 1000);
  const pad = (n) => String(n).padStart(2, '0');
  return `${kst.getUTCFullYear()}-${pad(kst.getUTCMonth() + 1)}-${pad(kst.getUTCDate())}T${pad(kst.getUTCHours())}:${pad(kst.getUTCMinutes())}:${pad(kst.getUTCSeconds())}+09:00`;
}
if (statusCode >= 400) {
  return [{ json: { _status: statusCode, _error: true, message: body.msg || body.message || '변경 처리에 실패했습니다.' } }];
}
if (action === 'restore' && backupId) {
  const workflowStaticData = $getWorkflowStaticData('global');
  const backups = Array.isArray(workflowStaticData.legacyTxHistoryBackups) ? workflowStaticData.legacyTxHistoryBackups : [];
  const entry = backups.find((item) => item && item.backupId === backupId);
  if (entry) {
    entry.restoredAt = toKstTimestamp();
    entry.restoredRecordId = Number(body.Id || body.id || 0) || null;
    entry.restoreOperator = restoreMeta.operatorName || null;
  }
}
return [{
  json: {
    ok: true,
    action,
    backupId,
    record: action === 'delete' ? null : body,
    restoredRecordId: action === 'restore' ? (Number(body.Id || body.id || 0) || null) : null
  }
}];

const request = $('Validate Auth & Parse').first().json || {};
const workflowStaticData = $getWorkflowStaticData('global');
const backups = Array.isArray(workflowStaticData.legacyTxHistoryBackups) ? workflowStaticData.legacyTxHistoryBackups : [];
const sliced = backups.slice(0, request.limit || 100).map((entry) => ({
  backupId: entry.backupId,
  action: entry.action,
  recordId: entry.recordId,
  createdAt: entry.createdAt,
  operatorName: entry.operatorName,
  reason: entry.reason,
  restoredAt: entry.restoredAt || null,
  restoredRecordId: entry.restoredRecordId || null
}));
return [{ json: { ok: true, backups: sliced } }];
